  ('fire-eq-tech-moex-00875', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某防火構造建築物，供三溫暖洗澡區使用，面積為130 m2，天花板高度為3.6 m，請問下列何者 為適當的探測器？', '["差動式局限型探測器1種", "定溫式局限型探測器1種", "火焰式局限型探測器1種", "偵煙式局限型探測器1種"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
